import time, pytest

TOOL_LATENCY_BUDGETS_MS = {
    "search_documents": 500,
    "execute_sql": 1000,
    "call_external_api": 2000,
    "write_file": 200,
}

def timed_tool_call(tool_name: str, fn, *args, **kwargs):
    budget = TOOL_LATENCY_BUDGETS_MS.get(tool_name, 1000)
    start = time.perf_counter()
    result = fn(*args, **kwargs)
    elapsed_ms = (time.perf_counter() - start) * 1000
    assert elapsed_ms <= budget, (
        f"Tool '{tool_name}' exceeded latency budget: {elapsed_ms:.0f}ms > {budget}ms"
    )
    return result

@pytest.mark.integration
def test_search_documents_latency(search_tool):
    timed_tool_call("search_documents", search_tool, query="quarterly revenue")
